import{_ as a,c as o,o as t,a1 as s}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Cota Google Cloud: Consulta de Modelos | opencode-mystatus","description":"Aprenda a consultar a cota Google Cloud. Visualize a cota restante e tempo de redefinição dos modelos G3 Pro, G3 Image, G3 Flash e Claude.","frontmatter":{"title":"Cota Google Cloud: Consulta de Modelos | opencode-mystatus","sidebarTitle":"Google Cloud","subtitle":"Consulta de cota Google Cloud: G3 Pro/Image/Flash e Claude","description":"Aprenda a consultar a cota Google Cloud. Visualize a cota restante e tempo de redefinição dos modelos G3 Pro, G3 Image, G3 Flash e Claude.","tags":["Google Cloud","Antigravity","consulta de cota"],"prerequisite":["start-quick-start","start-using-mystatus"],"order":4},"headers":[],"relativePath":"pt/vbgate/opencode-mystatus/platforms/google-usage/index.md","filePath":"pt/vbgate/opencode-mystatus/platforms/google-usage/index.md"}'),i={name:"pt/vbgate/opencode-mystatus/platforms/google-usage/index.md"};function n(l,e,d,r,c,p){return t(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="consulta-de-cota-google-cloud-g3-pro-image-flash-e-claude" tabindex="-1">Consulta de cota Google Cloud: G3 Pro/Image/Flash e Claude <a class="header-anchor" href="#consulta-de-cota-google-cloud-g3-pro-image-flash-e-claude" aria-label="Permalink to &quot;Consulta de cota Google Cloud: G3 Pro/Image/Flash e Claude&quot;">​</a></h1><h2 id="o-que-voce-podera-fazer-apos-concluir" tabindex="-1">O que você poderá fazer após concluir <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-concluir" aria-label="Permalink to &quot;O que você poderá fazer após concluir&quot;">​</a></h2><ul><li>Visualizar a cota de 4 modelos de contas Google Cloud Antigravity</li><li>Entender o tempo de redefinição e porcentagem restante de cada modelo</li><li>Gerenciar o uso de cota de múltiplas contas Google Cloud</li></ul><h2 id="o-seu-problema-atual" tabindex="-1">O seu problema atual <a class="header-anchor" href="#o-seu-problema-atual" aria-label="Permalink to &quot;O seu problema atual&quot;">​</a></h2><p>O Google Cloud Antigravity fornece múltiplos modelos (G3 Pro, G3 Image, G3 Flash, Claude), cada modelo tem cota e tempo de redefinição independentes. Você precisa:</p><ul><li>Fazer login no console Google Cloud separadamente para ver o status de cada modelo</li><li>Calcular manualmente a cota restante e tempo de redefinição</li><li>Gerenciar múltiplas contas é ainda mais confuso</li></ul><h2 id="quando-usar-este-metodo" tabindex="-1">Quando usar este método <a class="header-anchor" href="#quando-usar-este-metodo" aria-label="Permalink to &quot;Quando usar este método&quot;">​</a></h2><p>Quando você:</p><ul><li>Quiser entender rapidamente a cota restante de todos os modelos Google Cloud</li><li>Precisar planejar a alocação de uso entre diferentes modelos</li><li>Tiver múltiplas contas Google Cloud que precisam de gerenciamento unificado</li></ul><h2 id="🎒-preparacao-antes-de-comecar" tabindex="-1">🎒 Preparação antes de começar <a class="header-anchor" href="#🎒-preparacao-antes-de-comecar" aria-label="Permalink to &quot;🎒 Preparação antes de começar&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Verificação prévia</p><ol><li><strong>Plugin mystatus instalado</strong>: Consulte <a href="/docs/opencodedocs/pt/vbgate/opencode-mystatus/start/quick-start/">Início rápido</a></li><li><strong>Autenticação Google Cloud configurada</strong>: Precisa primeiro instalar o plugin <a href="https://github.com/NoeFabris/opencode-antigravity-auth" target="_blank" rel="noreferrer">opencode-antigravity-auth</a> para completar a autenticação OAuth</li><li><strong>Arquivo de autenticação existe</strong>: <code>~/.config/opencode/antigravity-accounts.json</code> contém pelo menos uma conta</li></ol></div><h2 id="ideia-principal" tabindex="-1">Ideia principal <a class="header-anchor" href="#ideia-principal" aria-label="Permalink to &quot;Ideia principal&quot;">​</a></h2><p>O Google Cloud Antigravity usa o mecanismo OAuth para autenticação, cada conta tem um Refresh Token independente. O plugin mystatus irá:</p><ol><li>Ler <code>antigravity-accounts.json</code> para obter todas as contas configuradas</li><li>Usar Refresh Token para atualizar o Access Token</li><li>Chamar a API Google Cloud para obter a cota de todos os modelos</li><li>Exibir a cota e tempo de redefinição de 4 modelos agrupados por conta</li></ol><h2 id="modelos-suportados-google-cloud" tabindex="-1">Modelos suportados Google Cloud <a class="header-anchor" href="#modelos-suportados-google-cloud" aria-label="Permalink to &quot;Modelos suportados Google Cloud&quot;">​</a></h2><p>O mystatus exibe a cota dos seguintes 4 modelos:</p><table tabindex="0"><thead><tr><th>Nome de exibição</th><th>Chave do modelo (principal/alternativa)</th><th>Descrição</th></tr></thead><tbody><tr><td>G3 Pro</td><td><code>gemini-3-pro-high</code> / <code>gemini-3-pro-low</code></td><td>Gemini 3 Pro versão de alto desempenho</td></tr><tr><td>G3 Image</td><td><code>gemini-3-pro-image</code></td><td>Gemini 3 Pro geração de imagem</td></tr><tr><td>G3 Flash</td><td><code>gemini-3-flash</code></td><td>Gemini 3 Flash versão rápida</td></tr><tr><td>Claude</td><td><code>claude-opus-4-5-thinking</code> / <code>claude-opus-4-5</code></td><td>Claude Opus 4.5 modelo</td></tr></tbody></table><p><strong>Mecanismo de chave principal e alternativa</strong>:</p><ul><li>A resposta da API pode retornar apenas dados da chave principal ou alternativa</li><li>O mystatus tentará automaticamente obter a cota de qualquer chave</li><li>Por exemplo: se <code>gemini-3-pro-high</code> não tiver dados, tentará <code>gemini-3-pro-low</code></li></ul><h2 id="siga-me" tabindex="-1">Siga-me <a class="header-anchor" href="#siga-me" aria-label="Permalink to &quot;Siga-me&quot;">​</a></h2><h3 id="passo-1-executar-comando-de-consulta" tabindex="-1">Passo 1: Executar comando de consulta <a class="header-anchor" href="#passo-1-executar-comando-de-consulta" aria-label="Permalink to &quot;Passo 1: Executar comando de consulta&quot;">​</a></h3><p><strong>Por que</strong> Obter rapidamente informações de cota de todas as contas Google Cloud</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mystatus</span></span></code></pre></div><p><strong>O que você deve ver</strong> Contém informações de cota de todas as plataformas configuradas, onde a seção Google Cloud exibirá conteúdo semelhante ao seguinte:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Google Cloud Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Image   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Flash   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>Claude     2d 9h      ░░░░░░░░░░░░░░░░░░░░ 0%</span></span></code></pre></div><h3 id="passo-2-entender-o-formato-de-saida" tabindex="-1">Passo 2: Entender o formato de saída <a class="header-anchor" href="#passo-2-entender-o-formato-de-saida" aria-label="Permalink to &quot;Passo 2: Entender o formato de saída&quot;">​</a></h3><p><strong>Por que</strong> Localizar rapidamente informações principais: cota restante e tempo de redefinição</p><p>Cada formato de linha:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[nome do modelo] [tempo de redefinição] [barra de progresso] [porcentagem restante]</span></span></code></pre></div><p><strong>Explicação dos campos</strong>:</p><ul><li><strong>Nome do modelo</strong>: G3 Pro, G3 Image, G3 Flash, Claude</li><li><strong>Tempo de redefinição</strong>: Tempo restante até a próxima redefinição de cota (como <code>4h 59m</code>, <code>2d 9h</code>)</li><li><strong>Barra de progresso</strong>: Exibe visualmente a porcentagem restante</li><li><strong>Porcentagem restante</strong>: Valor numérico 0-100</li></ul><p><strong>O que você deve ver</strong> Cada modelo em uma linha, exibindo claramente a cota e tempo de redefinição</p><h3 id="passo-3-verificar-situacao-de-multiplas-contas" tabindex="-1">Passo 3: Verificar situação de múltiplas contas <a class="header-anchor" href="#passo-3-verificar-situacao-de-multiplas-contas" aria-label="Permalink to &quot;Passo 3: Verificar situação de múltiplas contas&quot;">​</a></h3><p><strong>Por que</strong> Se você tiver múltiplas contas Google Cloud, serão exibidas separadamente</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Image   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### another@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     2h 30m     ████████████░░░░░░░░░ 75%</span></span>
<span class="line"><span>G3 Image   2h 30m     ████████████░░░░░░░░░ 75%</span></span></code></pre></div><p><strong>O que você deve ver</strong> Cada conta em um bloco separado, contendo a cota de 4 modelos dessa conta</p><h3 id="passo-4-verificar-avisos-de-cota" tabindex="-1">Passo 4: Verificar avisos de cota <a class="header-anchor" href="#passo-4-verificar-avisos-de-cota" aria-label="Permalink to &quot;Passo 4: Verificar avisos de cota&quot;">​</a></h3><p><strong>Por que</strong> Evitar uso excessivo causando interrupção do serviço</p><p>Se a taxa de uso de qualquer modelo exceder 80%, um aviso será exibido:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     1h 30m     ████░░░░░░░░░░░░░░░ 20%</span></span>
<span class="line"><span>G3 Image   1h 30m     ████░░░░░░░░░░░░░░░ 20%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>⚠️ 使用率已达到或超过 80%</span></span></code></pre></div><p><strong>O que você deve ver</strong> Aviso de aviso aparece abaixo da lista de modelos da conta correspondente</p><h2 id="ponto-de-verificacao-✅" tabindex="-1">Ponto de verificação ✅ <a class="header-anchor" href="#ponto-de-verificacao-✅" aria-label="Permalink to &quot;Ponto de verificação ✅&quot;">​</a></h2><p>Complete as seguintes verificações para garantir que você fez corretamente:</p><ul><li>[ ] Após executar <code>/mystatus</code>, pode ver informações de cota Google Cloud</li><li>[ ] Pode entender os nomes e tempos de redefinição dos 4 modelos</li><li>[ ] Pode identificar barras de progresso e porcentagem restante</li><li>[ ] Se houver múltiplas contas, pode ver a cota de todas as contas</li></ul><h2 id="avisos-sobre-armadilhas" tabindex="-1">Avisos sobre armadilhas <a class="header-anchor" href="#avisos-sobre-armadilhas" aria-label="Permalink to &quot;Avisos sobre armadilhas&quot;">​</a></h2><h3 id="problema-1-nao-ve-cota-google-cloud" tabindex="-1">Problema 1: Não vê cota Google Cloud <a class="header-anchor" href="#problema-1-nao-ve-cota-google-cloud" aria-label="Permalink to &quot;Problema 1: Não vê cota Google Cloud&quot;">​</a></h3><p><strong>Possíveis causas</strong>:</p><ul><li>Plugin opencode-antigravity-auth não instalado</li><li>Autenticação OAuth Google não completada</li><li>Arquivo <code>antigravity-accounts.json</code> não existe ou está vazio</li></ul><p><strong>Solução</strong>:</p><ol><li>Instale o plugin opencode-antigravity-auth</li><li>Complete a autenticação seguindo as instruções do repositório GitHub</li><li>Execute <code>/mystatus</code> novamente</li></ol><h3 id="problema-2-alguma-conta-exibe-erro" tabindex="-1">Problema 2: Alguma conta exibe erro <a class="header-anchor" href="#problema-2-alguma-conta-exibe-erro" aria-label="Permalink to &quot;Problema 2: Alguma conta exibe erro&quot;">​</a></h3><p><strong>Possíveis causas</strong>:</p><ul><li>Refresh Token expirou</li><li>projectId ausente</li></ul><p><strong>Exemplo de erro</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>user@gmail.com: No project ID found</span></span></code></pre></div><p><strong>Solução</strong>:</p><ol><li>Reautentique a conta usando o plugin opencode-antigravity-auth</li><li>Certifique-se de definir corretamente o ID do projeto durante a autenticação</li></ol><h3 id="problema-3-modelo-exibe-ou-tempo-de-redefinicao-anormal" tabindex="-1">Problema 3: Modelo exibe &quot;-&quot; ou tempo de redefinição anormal <a class="header-anchor" href="#problema-3-modelo-exibe-ou-tempo-de-redefinicao-anormal" aria-label="Permalink to &quot;Problema 3: Modelo exibe &quot;-&quot; ou tempo de redefinição anormal&quot;">​</a></h3><p><strong>Possíveis causas</strong>:</p><ul><li>Campo resetTime da API está ausente ou com formato anormal</li><li>O modelo não tem informações de cota</li></ul><p><strong>Solução</strong>:</p><ul><li>Isso é normal, o mystatus exibirá &quot;-&quot; indicando que os dados não estão disponíveis</li><li>Se todos os modelos exibirem &quot;-&quot;, verifique a conexão de rede ou status da API Google Cloud</li></ul><h2 id="resumo-desta-secao" tabindex="-1">Resumo desta seção <a class="header-anchor" href="#resumo-desta-secao" aria-label="Permalink to &quot;Resumo desta seção&quot;">​</a></h2><ul><li>Google Cloud Antigravity suporta 4 modelos: G3 Pro, G3 Image, G3 Flash, Claude</li><li>Cada modelo tem cota e tempo de redefinição independentes</li><li>Suporta gerenciamento de múltiplas contas, cada conta exibida separadamente</li><li>Quando a taxa de uso exceder 80%, um aviso será exibido</li></ul><h2 id="proxima-secao" tabindex="-1">Próxima seção <a class="header-anchor" href="#proxima-secao" aria-label="Permalink to &quot;Próxima seção&quot;">​</a></h2><blockquote><p>A próxima seção aprenderemos <strong><a href="./../../advanced/google-setup/">Configuração avançada Google Cloud: múltiplas contas e gerenciamento de modelos</a></strong>.</p><p>Você aprenderá:</p><ul><li>Como adicionar e gerenciar múltiplas contas Google Cloud</li><li>Entender a relação de mapeamento de 4 modelos</li><li>Diferença entre projectId e managedProjectId</li></ul></blockquote><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do código-fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do código-fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver a localização do código-fonte</strong></summary><blockquote><p>Data de atualização: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do arquivo</th><th>Número da linha</th></tr></thead><tbody><tr><td>Configuração de modelo</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L69-L78" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>69-78</td></tr><tr><td>Lógica de consulta de conta</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L304-L370" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>304-370</td></tr><tr><td>Atualização de token</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L162-L184" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>162-184</td></tr><tr><td>Extração de cota</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L132-L157" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>132-157</td></tr><tr><td>Formatação de saída</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L265-L294" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>265-294</td></tr><tr><td>Definições de tipo</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts#L78-L94" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>78-94</td></tr></tbody></table><p><strong>Constantes principais</strong>:</p><ul><li><code>GOOGLE_QUOTA_API_URL = &quot;https://cloudcode-pa.googleapis.com/v1internal:fetchAvailableModels&quot;</code>: API de consulta de cota Google Cloud</li><li><code>GOOGLE_TOKEN_REFRESH_URL = &quot;https://oauth2.googleapis.com/token&quot;</code>: API de atualização de token OAuth</li><li><code>USER_AGENT = &quot;antigravity/1.11.9 windows/amd64&quot;</code>: User-Agent de solicitação de API</li></ul><p><strong>Funções principais</strong>:</p><ul><li><code>queryGoogleUsage()</code>: Consulta a cota de todas as contas Antigravity</li><li><code>fetchAccountQuota()</code>: Consulta a cota de uma única conta</li><li><code>extractModelQuotas()</code>: Extrai a cota de 4 modelos da resposta da API</li><li><code>formatAccountQuota()</code>: Formata a exibição de cota de uma única conta</li></ul><p><strong>Regras de mapeamento de modelos</strong>:</p><ul><li>G3 Pro suporta <code>gemini-3-pro-high</code> e <code>gemini-3-pro-low</code>, prioridade para chave principal</li><li>Claude suporta <code>claude-opus-4-5-thinking</code> e <code>claude-opus-4-5</code>, prioridade para chave principal</li><li>G3 Image e G3 Flash têm apenas uma chave</li></ul></details>`,69)])])}const g=a(i,[["render",n]]);export{m as __pageData,g as default};
